;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6, 7, 8, 10]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="Welcome to Sapphire City!"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

[texton]
I tried to put my hand on the door, but it was tightly closed and would not budge.[k]
[name n=Voice]「Outsiders aren't allowed in here! Go home!」[k]
[if exp='o.人身売買の証拠をつかめ.accepted']
	[リーダー f=06]「...」[k]
	Well, there's no way a criminal organization would let you in so easily... Is there anywhere that could be infiltrated?
	 [k]
[endif]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="Count's Manor"

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@roadguide w="Sapphire City" e="Northrop Village"

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] onObjectTrigger

@notice text=Cemetery

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger || inSearching

@grave

[eventoff]
;-------------------------------------------------------------------------------
*event_7
;[exp] onObjectTrigger || inSearching

@grave monster=ゾンビ

[eventoff]
;-------------------------------------------------------------------------------
*event_8
;[exp] onObjectTrigger || inSearching || (onUseEventItem && [o.気付けの花, o.毒消しの花].has(game.curItem))

[if exp='o.墓参り.flag == 1 && game.onUseEventItem']
	@se f=period
	@wait time=500
	@notice text="<y>I laid flowers on Stella's grave!"
	@eval exp='game.itemWin.curChara.ejectItem(game.curItem, game.itemWin.curChara.reservedGrid)'
	@eval exp='o.墓参り.flag = 2'
[else]
	@grave name=Stella
	@notice text="Flowers are placed on the grave." cond='o.墓参り.flag == 2'
[endif]

[eventoff]
;-------------------------------------------------------------------------------
*event_9
;[exp] party.lastIsMove

@fg c=slime_01 left=450 top=386
[texton w=1]
[name n=Salesperson f=slime_01]「Hello. We're selling tickets to Yanek Hot Springs here.[r]They're 800G each. Would you like to buy one?」[k]
[textoff]

@question title="Would you like to buy a hot spring ticket?"

[if exp='tf.result']
	[if exp='game.party.gold < 800']
		@se f=buzzer
		[texton w=1]
		[name n=Salesperson f=slime_01]「You don't have enough money. I'm sorry, but I can't give you another freebie.」[k]
		[textoff]
	[else]
		@eval exp='game.party.gold -= 800'
		@se f=coin
		@getitem item=温泉チケット message="<y>I paid 800G for a hot spring ticket!"
	[endif]
[endif]
@clf

[eventoff]
;-------------------------------------------------------------------------------
*event_10
;[exp] onObjectTrigger

@notice text="Ahead: the Cave of Experience"

[eventoff]
;-------------------------------------------------------------------------------
